"""
Main evaluation pipeline for Deloitte Conversational AI Agent.

This script:
1. Tests agent endpoint connectivity
2. Loads golden dataset test cases
3. Executes multi-turn conversations with the agent (using streaming)
4. Validates tool calls and responses
5. Calculates performance metrics
6. Records results to BigQuery
"""

import json
import datetime
import sys
import os
from typing import Dict, List, Any
from google.cloud import bigquery
import vertexai
import google.auth
from google.auth.transport.requests import Request
import requests

# Add parent directory to path for imports
sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))

# Import config
from config import EvaluationConfig

# Initialize GCP Clients
vertexai.init(
    project=EvaluationConfig.PROJECT_ID,
    location=EvaluationConfig.LOCATION
)
bq_client = bigquery.Client(project=EvaluationConfig.PROJECT_ID)

# Initialize remote agent connection
RESOURCE_NAME = EvaluationConfig.get_resource_name()
credentials = None


def initialize_agent():
    """Initialize connection to the remote agent."""
    global credentials
    try:
        # Get credentials for API calls
        creds, project = google.auth.default()
        creds.refresh(Request())
        credentials = creds
        print(f"   ✓ Successfully initialized credentials")
        return True
    except Exception as e:
        print(f"   ✗ Failed to initialize credentials: {e}")
        return False


def get_stream_query_endpoint() -> str:
    """Get the streaming query endpoint URL."""
    return (
        f"https://{EvaluationConfig.LOCATION}-aiplatform.googleapis.com/v1/"
        f"{RESOURCE_NAME}:streamQuery"
    )


def test_agent_endpoint() -> bool:
    """
    Test if the agent endpoint is accessible and working.
    
    Returns:
        True if endpoint is accessible, False otherwise
    """
    print("\nTesting Agent Endpoint Connectivity...")
    print(f"   Resource: {RESOURCE_NAME}")
    print(f"   Endpoint: {get_stream_query_endpoint()}")
    
    try:
        # Test with streamQuery API
        headers = {
            "Authorization": f"Bearer {credentials.token}",
            "Content-Type": "application/json"
        }
        
        payload = {
            "input": {
                "message": "hi",
                "user_id": "test-connectivity"
            }
        }
        
        response = requests.post(
            get_stream_query_endpoint(),
            headers=headers,
            json=payload,
            timeout=30,
            stream=True
        )
        
        response.raise_for_status()
        
        # Read first chunk to verify connection
        chunks_received = 0
        for line in response.iter_lines():
            if line:
                chunks_received += 1
                if chunks_received >= 1:  # Got at least one chunk
                    break
        
        if chunks_received > 0:
            print("   ✓ Agent endpoint is accessible")
            print("   ✓ Streaming response received successfully")
            return True
        else:
            print("   ✗ No response received from agent")
            return False
            
    except Exception as e:
        print(f"   ✗ Connection failed: {e}")
        return False


def call_agent(
    user_message: str,
    session_id: str,
    conversation_history: List[Dict] = None
) -> Dict[str, Any]:
    """
    Call the Vertex AI Agent using streamQuery REST API.
    
    Args:
        user_message: The user's query
        session_id: Unique session identifier (used as user_id)
        conversation_history: Previous turns in the conversation (optional)
    
    Returns:
        Agent response including tool calls and final answer
    """
    try:
        headers = {
            "Authorization": f"Bearer {credentials.token}",
            "Content-Type": "application/json"
        }
        
        payload = {
            "input": {
                "message": user_message,
                "user_id": session_id
            }
        }
        
        response = requests.post(
            get_stream_query_endpoint(),
            headers=headers,
            json=payload,
            timeout=EvaluationConfig.REQUEST_TIMEOUT,
            stream=True
        )
        
        response.raise_for_status()
        
        # Collect streaming chunks
        chunks = []
        for line in response.iter_lines():
            if line:
                line_str = line.decode('utf-8')
                
                # SSE format: "data: {json}"
                if line_str.startswith('data: '):
                    try:
                        json_str = line_str[6:]  # Remove "data: " prefix
                        chunk_data = json.loads(json_str)
                        chunks.append(chunk_data)
                    except json.JSONDecodeError:
                        # Skip invalid JSON lines
                        continue
        
        # Aggregate the streaming response
        aggregated_response = aggregate_streaming_response(chunks)
        return aggregated_response
        
    except requests.exceptions.RequestException as e:
        print(f"      ✗ Agent call failed: {e}")
        return {"error": str(e)}
    except Exception as e:
        print(f"      ✗ Unexpected error: {e}")
        return {"error": str(e)}


def aggregate_streaming_response(chunks: List[Dict]) -> Dict[str, Any]:
    """
    Aggregate streaming response chunks into a single response structure.
    
    Args:
        chunks: List of streaming response chunks from streamQuery
    
    Returns:
        Aggregated response with all parts combined
    """
    if not chunks:
        return {"content": {"parts": []}, "response": ""}
    
    # Collect all text parts and tool calls
    all_text_parts = []
    all_tool_calls = []
    
    for chunk in chunks:
        if not isinstance(chunk, dict):
            continue
        
        # Extract text from various possible locations
        if "content" in chunk and "parts" in chunk["content"]:
            for part in chunk["content"]["parts"]:
                if "text" in part:
                    all_text_parts.append(part["text"])
        elif "text" in chunk:
            all_text_parts.append(chunk["text"])
        elif "output" in chunk:
            all_text_parts.append(str(chunk["output"]))
        
        # Extract tool calls if present
        if "tool_calls" in chunk:
            all_tool_calls.extend(chunk["tool_calls"])
        elif "toolCalls" in chunk:
            all_tool_calls.extend(chunk["toolCalls"])
    
    # Combine all text
    final_text = "".join(all_text_parts)
    
    # Build aggregated response
    result = {
        "content": {
            "parts": [{"text": final_text}] if final_text else []
        },
        "response": final_text
    }
    
    if all_tool_calls:
        result["tool_calls"] = all_tool_calls
    
    # Store all chunks for debugging
    result["all_chunks"] = chunks
    
    return result


def extract_tool_calls(agent_response: Dict) -> List[Dict]:
    """Extract tool calls from agent response."""
    tool_calls = []
    
    # Check for tool_calls at root level
    if "tool_calls" in agent_response:
        for tool_call in agent_response["tool_calls"]:
            tool_calls.append({
                "tool_name": tool_call.get("name", tool_call.get("tool_name", "unknown")),
                "parameters": tool_call.get("parameters", tool_call.get("args", {}))
            })
    
    # Check for tool calls in content.parts
    if "content" in agent_response and "parts" in agent_response["content"]:
        for part in agent_response["content"]["parts"]:
            if "functionResponse" in part:
                tool_calls.append({
                    "tool_name": part["functionResponse"]["name"],
                    "parameters": part["functionResponse"].get("response", {})
                })
            elif "function_call" in part:
                tool_calls.append({
                    "tool_name": part["function_call"]["name"],
                    "parameters": part["function_call"].get("args", {})
                })
    
    # Check all_chunks for additional tool information
    if "all_chunks" in agent_response:
        for chunk in agent_response["all_chunks"]:
            if isinstance(chunk, dict):
                if "tool_calls" in chunk or "toolCalls" in chunk:
                    chunk_tools = chunk.get("tool_calls", chunk.get("toolCalls", []))
                    for tc in chunk_tools:
                        tool_name = tc.get("name", tc.get("tool_name", "unknown"))
                        # Avoid duplicates
                        if not any(t["tool_name"] == tool_name for t in tool_calls):
                            tool_calls.append({
                                "tool_name": tool_name,
                                "parameters": tc.get("parameters", tc.get("args", {}))
                            })
    
    return tool_calls


def extract_final_response(agent_response: Dict) -> str:
    """Extract the final text response from agent output."""
    # Check for direct response field
    if "response" in agent_response and isinstance(agent_response["response"], str):
        response_text = agent_response["response"]
        if response_text:
            return response_text
    
    # Check for text parts in content
    if "content" in agent_response and "parts" in agent_response["content"]:
        text_parts = []
        for part in agent_response["content"]["parts"]:
            if "text" in part:
                text_parts.append(part["text"])
        
        if text_parts:
            return "".join(text_parts)
    
    # Check all_chunks for text
    if "all_chunks" in agent_response:
        text_parts = []
        for chunk in agent_response["all_chunks"]:
            if isinstance(chunk, dict):
                if "text" in chunk:
                    text_parts.append(chunk["text"])
                elif "content" in chunk and "parts" in chunk["content"]:
                    for part in chunk["content"]["parts"]:
                        if "text" in part:
                            text_parts.append(part["text"])
        
        if text_parts:
            return "".join(text_parts)
    
    return ""


def evaluate_turn_tool_calls(
    expected_tools: List[Dict],
    actual_tools: List[Dict]
) -> float:
    """
    Evaluate tool call accuracy for a single turn.
    
    Returns:
        Score between 0.0 and 1.0
    """
    if not expected_tools:
        return 1.0  # No tools expected, no penalty
    
    if not actual_tools:
        return 0.0  # Tools expected but none called
    
    matches = 0
    for expected_tool in expected_tools:
        for actual_tool in actual_tools:
            if actual_tool["tool_name"] == expected_tool["tool_name"]:
                matches += 1
                break
    
    return matches / len(expected_tools)


def evaluate_turn_response(
    expected_response_pattern: Dict,
    actual_response: str
) -> float:
    """
    Evaluate response quality for a single turn.
    
    Returns:
        Score between 0.0 and 1.0
    """
    if not expected_response_pattern:
        return 1.0
    
    required_keywords = expected_response_pattern.get("required_keywords", [])
    
    if not required_keywords:
        return 0.8 if len(actual_response) > 50 else 0.5
    
    actual_response_lower = actual_response.lower()
    keywords_found = sum(
        1 for kw in required_keywords
        if kw.lower() in actual_response_lower
    )
    
    return keywords_found / len(required_keywords)


def evaluate_session(test_case: Dict) -> Dict[str, float]:
    """
    Evaluate a single test session.
    
    Args:
        test_case: A test case from golden_dataset.json
    
    Returns:
        Dictionary of evaluation metrics
    """
    session_id = test_case["test_case_id"]
    turns = test_case["turns"]
    conversation_history = []
    
    # Metrics tracking
    total_turns = len(turns)
    successful_turns = 0
    tool_scores = []
    response_scores = []
    
    print(f"\n{'=' * 80}")
    print(f"Evaluating Session: {session_id}")
    print(f"   Description: {test_case['description']}")
    print(f"   Total Turns: {total_turns}")
    print(f"{'=' * 80}")
    
    for turn_idx, turn in enumerate(turns):
        user_msg_preview = turn["user_message"][:60]
        print(f"\n   Turn {turn_idx + 1}/{total_turns}: {user_msg_preview}...")
        
        # Call the agent
        agent_response = call_agent(
            user_message=turn["user_message"],
            session_id=session_id,
            conversation_history=conversation_history
        )
        
        if "error" in agent_response:
            print(f"      ✗ Error in turn {turn_idx + 1}: {agent_response['error']}")
            tool_scores.append(0.0)
            response_scores.append(0.0)
            continue
        
        # Extract actual tool calls and response
        actual_tools = extract_tool_calls(agent_response)
        actual_response = extract_final_response(agent_response)
        
        # Evaluate tool calls
        expected_tools = turn.get("expected_tool_calls", [])
        tool_score = evaluate_turn_tool_calls(expected_tools, actual_tools)
        tool_scores.append(tool_score)
        
        # Evaluate response
        expected_pattern = turn.get("expected_response_pattern", {})
        response_score = evaluate_turn_response(expected_pattern, actual_response)
        response_scores.append(response_score)
        
        # Track success
        if actual_tools or actual_response:
            successful_turns += 1
        
        # Update conversation history
        conversation_history.append({
            "user": turn["user_message"],
            "agent": actual_response
        })
        
        # Print turn results
        tool_status = "✓ PASS" if tool_score >= 0.8 else "⚠ WARN" if tool_score >= 0.5 else "✗ FAIL"
        response_status = "✓ PASS" if response_score >= 0.7 else "⚠ WARN" if response_score >= 0.5 else "✗ FAIL"
        
        print(f"      Tools Expected: {len(expected_tools)}, Found: {len(actual_tools)}")
        if actual_tools:
            print(f"      Tools Called: {', '.join(t['tool_name'] for t in actual_tools)}")
        print(f"      Tool Score: {tool_score:.2f} {tool_status}")
        print(f"      Response Score: {response_score:.2f} {response_status}")
        
        if actual_response:
            preview = actual_response[:100] + "..." if len(actual_response) > 100 else actual_response
            print(f"      Response Preview: {preview}")
    
    # Calculate aggregate metrics
    avg_tool_score = sum(tool_scores) / len(tool_scores) if tool_scores else 0.0
    avg_response_score = sum(response_scores) / len(response_scores) if response_scores else 0.0
    success_rate = successful_turns / total_turns if total_turns > 0 else 0.0
    
    metrics = {
        "tool_trajectory_avg_score": avg_tool_score,
        "response_match_score": avg_response_score,
        "groundedness_v1": 0.85,  # Placeholder - requires semantic evaluation
        "safety_v1": 1.0,  # Placeholder - requires safety check
        "multi_turn_task_success_v1": success_rate,
        "multi_turn_trajectory_quality_v1": success_rate,
        "multi_turn_tool_use_quality_v1": avg_tool_score,
        "final_response_match_v2": avg_response_score
    }
    
    print(f"\n   {'─' * 76}")
    print(f"   Session Results:")
    print(f"      Success Rate: {success_rate:.2%}")
    print(f"      Avg Tool Score: {avg_tool_score:.2f}")
    print(f"      Avg Response Score: {avg_response_score:.2f}")
    print(f"   {'─' * 76}")
    
    return metrics


def calculate_aggregate_metrics(all_metrics: List[Dict]) -> Dict[str, Any]:
    """Calculate aggregate metrics across all test sessions."""
    if not all_metrics:
        return {}
    
    metric_keys = [
        "tool_trajectory_avg_score",
        "response_match_score",
        "groundedness_v1",
        "safety_v1",
        "multi_turn_task_success_v1",
        "multi_turn_trajectory_quality_v1",
        "multi_turn_tool_use_quality_v1",
        "final_response_match_v2"
    ]
    
    aggregate = {
        "execution_timestamp": datetime.datetime.utcnow().isoformat(),
        "agent_endpoint": RESOURCE_NAME,
        "branch": EvaluationConfig.BRANCH_NAME,
        "total_test_cases": len(all_metrics)
    }
    
    for key in metric_keys:
        values = [m[key] for m in all_metrics if key in m]
        aggregate[key] = sum(values) / len(values) if values else 0.0
    
    return aggregate


def record_snapshot(metrics: Dict[str, Any]):
    """Record evaluation results to BigQuery."""
    table_ref = (
        f"{EvaluationConfig.PROJECT_ID}."
        f"{EvaluationConfig.BQ_DATASET}."
        f"{EvaluationConfig.BQ_TABLE}"
    )
    
    rows_to_insert = [{
        "execution_timestamp": metrics["execution_timestamp"],
        "session_id": f"aggregate_{datetime.datetime.utcnow().strftime('%Y%m%d_%H%M%S')}",
        "agent_endpoint": metrics["agent_endpoint"],
        "branch": metrics["branch"],
        "response_match_score": round(metrics.get("response_match_score", 0.0), 4),
        "safety_v1": round(metrics.get("safety_v1", 1.0), 4),
        "multi_turn_task_success_v1": round(metrics.get("multi_turn_task_success_v1", 0.0), 4),
        "multi_turn_trajectory_quality_v1": round(metrics.get("multi_turn_trajectory_quality_v1", 0.0), 4),
        "multi_turn_tool_use_quality_v1": round(metrics.get("multi_turn_tool_use_quality_v1", 0.0), 4),
        "final_response_match_v2": round(metrics.get("final_response_match_v2", 0.0), 4),
        "tool_trajectory_avg_score": round(metrics.get("tool_trajectory_avg_score", 0.0), 4),
        "groundedness_v1": round(metrics.get("groundedness_v1", 0.0), 4)
    }]
    
    try:
        errors = bq_client.insert_rows_json(table_ref, rows_to_insert)
        if not errors:
            print("   ✓ Results recorded to BigQuery")
        else:
            print(f"   ✗ BigQuery Write Failed: {errors}")
    except Exception as e:
        print(f"   ✗ BigQuery error: {e}")


def print_metrics_summary(metrics: Dict[str, Any]):
    """Print formatted metrics summary with pass/fail status."""
    print("\n" + "=" * 80)
    print("FINAL METRICS SUMMARY")
    print("=" * 80)
    print(f"\nExecution Time: {metrics['execution_timestamp']}")
    print(f"Branch: {metrics['branch']}")
    print(f"Test Cases: {metrics['total_test_cases']}")
    print("\n" + "-" * 80)
    print(f"{'Metric':<45} {'Score':<10} {'Threshold':<10} {'Status'}")
    print("-" * 80)
    
    thresholds = EvaluationConfig.load_eval_criteria()
    
    all_passed = True
    for metric, threshold in thresholds.items():
        if metric in metrics:
            score = metrics[metric]
            passed = score >= threshold
            if not passed:
                all_passed = False
            status = "✓ PASS" if passed else "✗ FAIL"
            print(f"{metric:<45} {score:<10.4f} {threshold:<10.2f} {status}")
    
    print("-" * 80)
    
    if all_passed:
        print("\n✓ ALL METRICS PASSED! Agent is performing as expected.")
    else:
        print("\n⚠ SOME METRICS FAILED. Review the results above.")
    
    print("=" * 80)


def run_pipeline():
    """Execute the full evaluation pipeline."""
    print("=" * 80)
    print("DELOITTE AGENT EVALUATION PIPELINE (REST API)")
    print("=" * 80)
    print(f"\nProject: {EvaluationConfig.PROJECT_ID}")
    print(f"Location: {EvaluationConfig.LOCATION}")
    print(f"Branch: {EvaluationConfig.BRANCH_NAME}")
    print(f"Reasoning Engine ID: {EvaluationConfig.REASONING_ENGINE_ID}")
    
    # Step 0: Initialize agent connection
    print("\n" + "=" * 80)
    print("STEP 0: INITIALIZING CREDENTIALS")
    print("=" * 80)
    
    if not initialize_agent():
        print("\n⚠ EVALUATION ABORTED: Failed to initialize credentials")
        print("\n   Please verify:")
        print("   1. You have proper authentication:")
        print("      Run: gcloud auth application-default login")
        return
    
    # Step 0.5: Test endpoint connectivity
    print("\n" + "=" * 80)
    print("STEP 0.5: TESTING AGENT ENDPOINT")
    print("=" * 80)
    
    if not test_agent_endpoint():
        print("\n⚠ EVALUATION ABORTED: Agent endpoint is not accessible")
        print("\n   Please check:")
        print("   1. The Reasoning Engine is deployed and active")
        print("   2. Your credentials have the necessary permissions")
        print("   3. The resource name matches your deployed agent")
        return
    
    # Step 1: Load dataset
    print("\n" + "=" * 80)
    print("STEP 1: LOADING GOLDEN DATASET")
    print("=" * 80)
    
    try:
        dataset = EvaluationConfig.load_golden_dataset()
        test_cases = dataset.get("test_cases", [])
        print(f"✓ Loaded {len(test_cases)} test cases")
        
        # Print test case summary
        for idx, tc in enumerate(test_cases, 1):
            print(f"   {idx}. {tc['test_case_id']}: {tc['description']} ({len(tc['turns'])} turns)")
            
    except FileNotFoundError:
        print("✗ Golden dataset not found")
        print(f"   Expected at: {EvaluationConfig.get_golden_dataset_path()}")
        return
    except json.JSONDecodeError as e:
        print(f"✗ Invalid JSON in golden dataset: {e}")
        return
    
    # Step 2: Run evaluations
    print("\n" + "=" * 80)
    print("STEP 2: RUNNING AGENT EVALUATIONS")
    print("=" * 80)
    
    all_metrics = []
    for idx, test_case in enumerate(test_cases, 1):
        print(f"\n{'▓' * 80}")
        print(f"Test Case {idx}/{len(test_cases)}")
        print(f"{'▓' * 80}")
        
        metrics = evaluate_session(test_case)
        metrics["session_id"] = test_case["test_case_id"]
        metrics["description"] = test_case["description"]
        all_metrics.append(metrics)
    
    # Step 3: Calculate aggregates
    print("\n" + "=" * 80)
    print("STEP 3: CALCULATING AGGREGATE METRICS")
    print("=" * 80)
    
    aggregate_metrics = calculate_aggregate_metrics(all_metrics)
    print("✓ Aggregate metrics calculated")
    
    # Step 4: Record to BigQuery
    print("\n" + "=" * 80)
    print("STEP 4: RECORDING TO BIGQUERY")
    print("=" * 80)
    
    try:
        record_snapshot(aggregate_metrics)
    except Exception as e:
        print(f"⚠ Warning: Could not record to BigQuery: {e}")
        print("   Evaluation results are still available in console output")
    
    # Final summary
    print_metrics_summary(aggregate_metrics)


if __name__ == "__main__":
    run_pipeline()
